#include "XSbench_header.h"

unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype)
{
	double start = get_time();

	int * verification_array_host = (int *) malloc((size_t)in.lookups * sizeof(int));
	assert(verification_array_host != NULL);

	double stop = get_time();
	if( mype == 0 ) printf("OpenCL initialization time: %.3lf seconds\n", stop-start);
	start = stop;

	if( mype == 0 )
	{
		border_print();
		center_print("SIMULATION", 79);
		border_print();
	}

	if( mype == 0 ) printf("Running event based simulation...\n");

	#pragma omp parallel for schedule(static)
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, (uint64_t)(2ULL * (uint64_t)i));

		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		double macro_xs_vector[5] = {0};

		calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			SD.num_nucs,
			SD.concs,
			SD.unionized_energy_array,
			SD.index_grid,
			SD.nuclide_grid,
			SD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			SD.max_num_nucs
		);

		double max = -1.0;
		int max_idx = 0;
		for( int j = 0; j < 5; j++ )
		{
			if( macro_xs_vector[j] > max )
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification_array_host[i] = max_idx + 1;
	}

	stop = get_time();

	if( mype == 0 ) printf("Reducing verification value...\n");

	unsigned long long verification = 0;
	for( int l = 0; l < in.lookups; l++ )
		verification += (unsigned long long)verification_array_host[l];

	if( mype == 0 ) printf("Simulation + Verification Reduction Runtime: %.3lf seconds\n", stop-start);

	free(verification_array_host);

	return verification;
}

